create or replace function UpdateInheritPortalPerms(&&ObjId&& bigint, &&OnlyChildren&& integer) returns void
as $$
declare v_UserMask bigint = 72057594037927936; v_TableRecord record;
begin
for v_TableRecord in select * from UpdatePortalPermsRec($1) where $2 = 0 or &&CurrentId&& <> $1 loop
begin
if (v_TableRecord.&&ParentId&& is not null) then begin delete from &&PortalObjectPermission&& where &&PortalObject&& = v_TableRecord.&&CurrentId&& and &&InheritedFromFolder&& is not null; insert into &&PortalObjectPermission&& (&&Id&&, &&Uid&&, &&PortalObject&&, &&Group&&, &&InheritedFromFolder&&, &&OrganizationItemEmployee&&, &&OrganizationItemPosition&&, &&PermissionId&&, &&PermissionRole&&, &&User&&, &&UserSecuritySetCacheId&& ) select (nextval('G_PortalObjectPermission')) as &&Id&&, '00000000-0000-0000-0000-000000000000', v_TableRecord.&&CurrentId&&, pdp.&&Group&&, (case when pdp.&&InheritedFromFolder&& is null then v_TableRecord.&&ParentId&& else pdp.&&InheritedFromFolder&& end) as InheritedFromFolder, pdp.&&OrganizationItemEmployee&&, pdp.&&OrganizationItemPosition&&, pdp.&&PermissionId&&, pdp.&&PermissionRole&&, (case when pdp.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then v_TableRecord.&&CreationAuthor&& else pdp.&&User&& end) as &&User&&, (case when pdp.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then (v_TableRecord.&&CreationAuthor&& | v_UserMask) else pdp.&&UserSecuritySetCacheId&& end) as &&UserSecuritySetCacheId&& from &&PortalObjectPermission&& pdp where pdp.&&PortalObject&& = v_TableRecord.&&ParentId&&; end; end if;
end; end loop; end
$$ language plpgsql;
